exports.handler = async (event) => {
  const headers = {
    "Content-Type": "application/json",
    "Access-Control-Allow-Origin": "*",
    "Cache-Control": "public, max-age=3600",
  };

  try {
    const params = event.queryStringParameters || {};
    const origin = params.origin;
    const destination = params.destination;
    const day = params.day || "weekday"; // weekday or weekend

    if (!origin || !destination) {
      // Return list of available station pairs
      const weekdayPairs = Object.keys(WEEKDAY);
      const weekendPairs = Object.keys(WEEKEND);
      return {
        statusCode: 200,
        headers,
        body: JSON.stringify({
          message: "Provide origin and destination params. Available pairs listed below.",
          weekday_pairs: weekdayPairs.length,
          weekend_pairs: weekendPairs.length,
          example: "?origin=maplewood&destination=pennstation&day=weekday",
        }),
      };
    }

    const key = `${origin}__${destination}`;
    const schedules = day === "weekend" ? WEEKEND : WEEKDAY;
    const trains = schedules[key] || [];

    return {
      statusCode: 200,
      headers,
      body: JSON.stringify({
        origin,
        destination,
        day,
        count: trains.length,
        trains,
      }),
    };
  } catch (err) {
    return {
      statusCode: 500,
      headers,
      body: JSON.stringify({ error: err.message }),
    };
  }
};
